class Solution(object):
    def minCost(self, n, cost):
        INF = float('inf')
        half = n // 2

        # dp[c1][c2] = min cost using colors c1 for current left house,
        # c2 for current right house (equidistant partner)
        # c1 != c2 (equidistant constraint)
        # Initialize with the outermost pair (index 0 and index n-1)
        dp = [[INF] * 3 for _ in range(3)]
        for c1 in range(3):
            for c2 in range(3):
                if c1 != c2:
                    dp[c1][c2] = cost[0][c1] + cost[n - 1][c2]

        # Process pairs from outside in
        for i in range(1, half):
            j = n - 1 - i  # partner index
            new_dp = [[INF] * 3 for _ in range(3)]
            for c1 in range(3):  # color for house i
                for c2 in range(3):  # color for house j
                    if c1 == c2:
                        continue
                    # Prev left color must differ from c1 (adjacency: house i-1 and i)
                    # Prev right color must differ from c2 (adjacency: house j and j+1)
                    for pc1 in range(3):
                        if pc1 == c1:
                            continue
                        for pc2 in range(3):
                            if pc2 == c2:
                                continue
                            if dp[pc1][pc2] == INF:
                                continue
                            val = dp[pc1][pc2] + cost[i][c1] + cost[j][c2]
                            if val < new_dp[c1][c2]:
                                new_dp[c1][c2] = val
            dp = new_dp

        return min(dp[c1][c2] for c1 in range(3) for c2 in range(3) if c1 != c2)
